#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    long long res,sl,sr,slr;
    bool bl,br,blr,brl;
}t[N<<2];

int n,q,a[N];

void Pushup(int cur,int l,int r){
    Node &x=t[cur*2],&y=t[cur*2+1],&p=t[cur];
    int mid=l+r>>1,nl=a[mid],nr=a[mid+1];

    if(x.br && y.bl){
        if(nl<nr){
            p.res=x.sr+y.res;
            p.bl=x.brl;
            p.br=y.br;
        }else{
            p.res=x.res+y.sl;
            p.bl=x.bl;
            p.br=y.blr;
        }
    }else{
        p.res=x.res+y.res;
        p.bl=x.bl;
        p.br=y.br;
    }
    // rs,bl,br

    if(x.blr && y.bl){
        if(nl<nr){
            p.sl=x.slr+y.res;
            p.blr=y.br;
        }else{
            p.sl=x.sl+y.sl;
            p.blr=y.blr;
        }
    }else{
        p.sl=x.sl+y.res;
        p.blr=y.br;
    }
    // sl,blr

    if(x.br && y.brl){
        if(nl<nr){
            p.sr=x.sr+y.sr;
            p.brl=x.brl;
        }else{
            p.sr=x.res+y.slr;
            p.brl=x.bl;
        }
    }else{
        p.sr=x.res+y.sr;
        p.brl=x.bl;
    }
    // sr,brl

    if(x.blr && y.brl){
        if(nl<nr)
            p.slr=x.slr+y.sr;
        else
            p.slr=x.sl+y.slr;
    }else
        p.slr=x.sl+y.sr;
    // slr
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]={a[l],0,0,0,1,1,0,0};
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    Pushup(cur,l,r);
}

void modify(int cur,int l,int r,int x){
	if(l==r){
		t[cur]={a[l],0,0,0,1,1,0,0};
		return;
	}
	int mid=l+r>>1;
	if(x<=mid)
		modify(cur*2,l,mid,x);
	else
		modify(cur*2+1,mid+1,r,x);
	Pushup(cur,l,r);
} 

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    scanf("%d",&q);
    while(q--){
        int x,y;
        scanf("%d%d",&x,&y);
        a[x]=y;
        modify(1,1,n,x);
        printf("%lld\n",t[1].res);
    }
    return 0;
}
